import{_ as a,o as t,c as i,ak as s}from"./chunks/framework.C44GrXwr.js";const u=JSON.parse('{"title":"Send Mail from Local Server","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/local-server/send-mail-from-local-server.md","filePath":"documentation/field-types/local-server/send-mail-from-local-server.md","lastUpdated":1772776319000}'),l={name:"documentation/field-types/local-server/send-mail-from-local-server.md"};function r(n,e,o,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="send-mail-from-local-server" tabindex="-1">Send Mail from Local Server <a class="header-anchor" href="#send-mail-from-local-server" aria-label="Permalink to “Send Mail from Local Server”">​</a></h1><p>Send emails directly from your local server. This field type is useful for automated notifications, sharing scraped results, or triggering email-based workflows.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h2><p>Before using this field type, ensure you have completed the following:</p><ol><li><strong>Install Local Server</strong>: Download and run the Local Server on your PC as described in the <strong><a href="/documentation/local-server/local-server.html#installation">Local Server Installation</a></strong> guide.</li><li><strong>Add Account</strong>: Add your email account in the Local Server dashboard as described in the <strong><a href="/documentation/local-server/mail-accounts.html">Mail Accounts</a></strong> guide.</li><li><strong>Verify Connection</strong>: Use the <strong>Test SMTP</strong> and <strong>Test IMAP</strong> buttons in the server dashboard to ensure that the server can successfully communicate with your email provider.</li></ol><p>Once the connection is verified, you can proceed with the field configuration below.</p><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to “Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><a href="#mail-account-address"><strong>Mail Account Address</strong></a></td><td>The email address configured on your local server.</td><td>Yes</td></tr><tr><td><a href="#to"><strong>To</strong></a></td><td>The recipient&#39;s email address.</td><td>Yes</td></tr><tr><td><a href="#subject"><strong>Subject</strong></a></td><td>The subject line of the email.</td><td>Yes</td></tr><tr><td><a href="#mail-body"><strong>Mail Body</strong></a></td><td>Set the email content in the <strong>Field Default Value</strong>.</td><td>Yes</td></tr><tr><td><a href="#are-you-using-html-in-mail-body-text"><strong>Are you using HTML in mail body text?</strong></a></td><td>Enable this if your mail body contains HTML tags.</td><td>No</td></tr></tbody></table><h2 id="configuration-details" tabindex="-1">Configuration Details <a class="header-anchor" href="#configuration-details" aria-label="Permalink to “Configuration Details”">​</a></h2><h3 id="mail-account-address" tabindex="-1">Mail Account Address <a class="header-anchor" href="#mail-account-address" aria-label="Permalink to “Mail Account Address”">​</a></h3><p>Enter the full email address of the sender account as configured on your local server.</p><ul><li><strong>Example:</strong> <code>noreply@yourdomain.com</code></li></ul><h3 id="to" tabindex="-1">To <a class="header-anchor" href="#to" aria-label="Permalink to “To”">​</a></h3><p>Specify the recipient&#39;s email address. You can use fixed addresses or <a href="/documentation/variable.html">Variables</a> to dynamically set the recipient.</p><ul><li><strong>Example:</strong> <code>recipient@example.com</code></li></ul><h3 id="subject" tabindex="-1">Subject <a class="header-anchor" href="#subject" aria-label="Permalink to “Subject”">​</a></h3><p>Enter the subject of the email.</p><ul><li><strong>Example:</strong> <code>Automation Update: Form Successfully Filled</code></li></ul><h3 id="mail-body" tabindex="-1">Mail Body <a class="header-anchor" href="#mail-body" aria-label="Permalink to “Mail Body”">​</a></h3><p>The content of the email is taken from the <strong>Field Default Value</strong> of this field configuration. You can include plain text or variables here.</p><ul><li><strong>Example:</strong> <code>Hello, the process is complete.</code></li></ul><h3 id="are-you-using-html-in-mail-body-text" tabindex="-1">Are you using HTML in mail body text? <a class="header-anchor" href="#are-you-using-html-in-mail-body-text" aria-label="Permalink to “Are you using HTML in mail body text?”">​</a></h3><p>If you want to send formatted emails (with bold text, links, or tables), enable this option and provide HTML code in the <strong>Mail Body</strong> (Field Default Value). You can also use <a href="/documentation/variable.html">Variables</a> within your HTML code for dynamic content.</p><p><strong>Example HTML Body:</strong></p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Hello &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{$firstName$}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;,&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Your application has been processed.&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;View Details&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div>`,25)])])}const g=a(l,[["render",r]]);export{u as __pageData,g as default};
